  "extends": ["//"],
  "tasks": {
    // A task that is used for detecting if any turborepo Rust sources change
    "rust-src": {
      "env": ["RUNNER_OS"],
      "inputs": [
        "$TURBO_ROOT$/version.txt",
        "$TURBO_ROOT$/crates/**/*.rs",
        // Rust crates
